import { DashboardShell, Badge } from '@/components/DashboardShell'
import { orders } from '@/lib/mock-data'

export default async function OrderDetail({ params }: { params: Promise<{ id: string }> }) {
  const { id } = await params
  const order = orders.find((item) => item.id === id) ?? orders[0]
  return <DashboardShell><header className="top"><div><div className="eyebrow">Order detail</div><h1 className="h1">{order.salesOrderNumber}</h1><p className="muted">{order.customerName} · Delivery {order.deliveryDate}</p></div><button className="btn red">Generate Serial + QR</button></header>{order.reviewRequired && <div className="card" style={{borderColor:'#fecaca',marginBottom:16}}><Badge tone="red">Review Required</Badge><h2>Zoho Sales Order changed after QR generation.</h2><p className="muted">Admin must accept Zoho changes, ignore changes, generate extra machine units, void extra units, or resolve with remarks. No generated serial will be deleted automatically.</p></div>}<section className="grid two"><div className="card"><h2>Line Items</h2><table className="table"><thead><tr><th>Item</th><th>SKU</th><th>Qty</th><th>Wooden</th></tr></thead><tbody>{order.lineItems.map((item)=><tr key={item.sku}><td>{item.itemName}</td><td>{item.sku}</td><td>{item.quantity}</td><td>{item.woodenPackingRequired?'Yes':'No'}</td></tr>)}</tbody></table></div><div className="card"><h2>Actions</h2><div className="machine"><button className="btn">Preview QR Labels</button><button className="btn light">Print QR Labels</button><button className="btn light">Send to Packaging</button><button className="btn light">Resolve Conflict</button></div></div></section><section className="card" style={{marginTop:16}}><h2>Machine Units</h2><div className="machine">{order.machines.map((m)=><div className="machine-row" key={m.id}><div><strong>{m.serialNumber}</strong><div className="muted">{m.itemName} · {m.sku}</div></div><Badge tone={m.status==='Dispatched'?'green':m.status==='Review Required'?'red':'blue'}>{m.status}</Badge><a className="btn light" href={`/m/${m.serialNumber}`}>Passport</a></div>)}</div></section></DashboardShell>
}
